module top_module(clock, reset_n, D, Q);input clock, reset_n;
input  [3:0] D;
output [3:0] Q;
reg    [3:0] accumulator_value; 


  always @(posedge clock)
    begin
      if (reset_n)
        accumulator_value <= 4'b0000;
      else
        accumulator_value <= accumulator_value + D;
    end
assign Q = accumulator_value;
endmodule
